@@ -1,3 +1,12 @@
-export function noop() {}
+import { db } from './db';
+
+export async function exportCsv(accountId: string): Promise<string> {
+  const rows = await db.activity.findMany({ where: { accountId } });
+  const header = 'id,type,at\n';
+  const body = rows.map((r) => `${r.id},${r.type},${r.at}`).join('\n');
+  // NOTE: no pagination — will OOM on large accounts
+  return header + body;
+}
